export function WorksEverywhere() {
  return (
    <section
      style={{
        backgroundColor: "#FAFAF7",
        paddingTop: "clamp(5rem, 10vw, 9rem)",
        paddingBottom: "clamp(5rem, 10vw, 9rem)",
        paddingLeft: "clamp(1.5rem, 5vw, 5rem)",
        paddingRight: "clamp(1.5rem, 5vw, 5rem)",
        textAlign: "center",
      }}
    >
      <h2
        style={{
          fontFamily: "'Instrument Serif', serif",
          fontSize: "clamp(3rem, 7vw, 6rem)",
          letterSpacing: "-0.04em",
          color: "#1A1A18",
          fontWeight: 400,
          lineHeight: 1.0,
          marginBottom: "clamp(1.25rem, 2vw, 1.75rem)",
        }}
      >
        Works Everywhere.
      </h2>

      <p
        style={{
          fontFamily: "'Plus Jakarta Sans', sans-serif",
          fontSize: "clamp(1.05rem, 1.5vw, 1.15rem)",
          color: "#6B6860",
          lineHeight: 1.7,
          maxWidth: "38rem",
          margin: "0 auto",
          marginBottom: "clamp(2.5rem, 4vw, 3.5rem)",
        }}
      >
        Speak naturally and watch your words appear perfectly in any text
        field — emails, documents, code, chat.
      </p>

      {/* App logos row */}
      <div
        style={{
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
          gap: "clamp(1.5rem, 4vw, 3.5rem)",
          flexWrap: "wrap",
        }}
      >
        {apps.map((app) => (
          <div
            key={app.name}
            style={{
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              gap: "0.5rem",
            }}
          >
            {app.icon}
            <span
              style={{
                fontFamily: "'IBM Plex Mono', monospace",
                fontSize: "0.75rem",
                color: "#6B6860",
                letterSpacing: "0.08em",
              }}
            >
              {app.name}
            </span>
          </div>
        ))}
      </div>
    </section>
  );
}
